#!/usr/bin/env node
import { readdirSync, readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';

const gnosisMathRoot = path.join(process.cwd(), 'open-source/gnosis-math/Gnosis');
const reportPath = path.join(
  process.cwd(),
  'open-source/gnosis-math/MCP_OPEN_OBLIGATIONS.md'
);

const serverRules = [
  [/amplituhedron|quantum|qkv|attention|wave|spectral|physics|particle|boson|fermion|vacuum|blackhole|black_hole/iu, 'quantum-mcp'],
  [/relativ|lorentz|gravity|gravit|cosmic|cosmolog|spacetime|hawking/iu, 'relativity-mcp'],
  [/thermo|heat|entropy|metabolism|temperature|landauer/iu, 'thermodynamics-mcp'],
  [/queue|ergodic|markov|harris|recurrence|stability|stationary/iu, 'ergodicity-mcp'],
  [/buley|buleyean|godformula|god_formula|kernel|sliver|clinamen|gnostic|void/iu, 'god-formula-mcp'],
  [/mesh|topolog|braid|knot|homology|betti|manifold|cobordism|fano|octonion|catmap|arnold|mckay|ade|langlands/iu, 'topology-mcp'],
  [/govern|constitution|law|justice|liability|compliance|torah|jubilee|rights/iu, 'governance-mcp'],
  [/market|hft|trading|finance|vwap|orderbook|netflix|economics|auction|tariff/iu, 'economics-mcp'],
  [/genom|dna|cancer|bio|immune|autoimmunity|cell|protein/iu, 'genomics-mcp'],
  [/sleep|dream/iu, 'sleep-mcp'],
  [/emotion|affect|anxiety|grief|forgive|recovery|therapy|mindful|psyche|conscious/iu, 'emotion-mcp'],
  [/language|linguistic|grammar|chomsky|poe|borges|leibniz|laplace|plato|aristotle|zeno|cicero|parable|witness/iu, 'philosophy-mcp'],
  [/security|adversarial|attack|deception|fraud|byzantine/iu, 'cybersecurity-mcp'],
  [/protocol|server|runtime|compiler|scheduler|forkracefold|fork_race_fold/iu, 'verification-mcp'],
];

function walkLeanFiles(directory, files = []) {
  for (const entry of readdirSync(directory, { withFileTypes: true })) {
    const fullPath = path.join(directory, entry.name);
    if (entry.isDirectory()) {
      walkLeanFiles(fullPath, files);
    } else if (entry.isFile() && entry.name.endsWith('.lean')) {
      files.push(fullPath);
    }
  }
  return files;
}

function moduleNameFromPath(filePath) {
  return path
    .relative(gnosisMathRoot, filePath)
    .replace(/\.lean$/u, '')
    .split(path.sep)
    .join('/');
}

function likelyServerForModule(moduleName) {
  for (const [pattern, server] of serverRules) {
    if (pattern.test(moduleName)) return server;
  }
  return 'verification-mcp';
}

function stripLeanCommentsPreserveLines(source) {
  let output = '';
  for (let index = 0; index < source.length; ) {
    if (source.startsWith('/-', index)) {
      let depth = 1;
      output += '  ';
      index += 2;
      while (index < source.length && depth > 0) {
        if (source.startsWith('/-', index)) {
          depth += 1;
          output += '  ';
          index += 2;
        } else if (source.startsWith('-/', index)) {
          depth -= 1;
          output += '  ';
          index += 2;
        } else {
          output += source[index] === '\n' ? '\n' : ' ';
          index += 1;
        }
      }
    } else if (source.startsWith('--', index)) {
      output += '  ';
      index += 2;
      while (index < source.length && source[index] !== '\n') {
        output += ' ';
        index += 1;
      }
    } else if (source[index] === '"') {
      output += ' ';
      index += 1;
      while (index < source.length) {
        if (source[index] === '\\') {
          output += '  ';
          index += 2;
        } else if (source[index] === '"') {
          output += ' ';
          index += 1;
          break;
        } else {
          output += source[index] === '\n' ? '\n' : ' ';
          index += 1;
        }
      }
    } else {
      output += source[index];
      index += 1;
    }
  }
  return output;
}

function scanObligations(filePath) {
  const source = readFileSync(filePath, 'utf8');
  const code = stripLeanCommentsPreserveLines(source);
  const lines = code.split('\n');
  const obligations = [];
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index];
    const lineNumber = index + 1;
    if (/\bsorry\b/u.test(line)) {
      obligations.push({ kind: 'sorry', lineNumber, snippet: line.trim() });
    }
    if (/\badmit\b/u.test(line)) {
      obligations.push({ kind: 'admit', lineNumber, snippet: line.trim() });
    }
    if (/^\s*axiom\s+/u.test(line)) {
      obligations.push({ kind: 'axiom', lineNumber, snippet: line.trim() });
    }
  }
  return obligations;
}

function summarizeKind(obligations, kind) {
  return obligations.filter((obligation) => obligation.kind === kind).length;
}

function renderReport(moduleAudits) {
  const byServer = new Map();
  for (const moduleAudit of moduleAudits) {
    const bucket = byServer.get(moduleAudit.server) ?? [];
    bucket.push(moduleAudit);
    byServer.set(moduleAudit.server, bucket);
  }

  const totalObligations = moduleAudits.reduce(
    (sum, moduleAudit) => sum + moduleAudit.obligations.length,
    0
  );

  const lines = [
    '# MCP Open Obligations',
    '',
    'Parent: [Gnosis Math](./README.md)',
    '',
    'Generated by `node open-source/gnosis/scripts/audit-gnosis-math-open-obligations.mjs`.',
    'The scanner ignores Lean comments and only counts code-token `sorry`, `admit`, and top-level `axiom` lines.',
    '',
    '## Summary',
    '',
    `- Modules with open obligations: ${moduleAudits.length}`,
    `- Total open obligation tokens: ${totalObligations}`,
    `- \`sorry\`: ${moduleAudits.reduce((sum, moduleAudit) => sum + summarizeKind(moduleAudit.obligations, 'sorry'), 0)}`,
    `- \`admit\`: ${moduleAudits.reduce((sum, moduleAudit) => sum + summarizeKind(moduleAudit.obligations, 'admit'), 0)}`,
    `- \`axiom\`: ${moduleAudits.reduce((sum, moduleAudit) => sum + summarizeKind(moduleAudit.obligations, 'axiom'), 0)}`,
    '',
    '## MCP Island Counts',
    '',
    '| MCP island | Modules | Obligations | sorry | admit | axiom |',
    '|---|---:|---:|---:|---:|---:|',
  ];

  for (const [server, modules] of [...byServer.entries()].sort(([a], [b]) =>
    a.localeCompare(b)
  )) {
    const obligations = modules.flatMap((moduleAudit) => moduleAudit.obligations);
    lines.push(
      `| ${server} | ${modules.length} | ${obligations.length} | ${summarizeKind(obligations, 'sorry')} | ${summarizeKind(obligations, 'admit')} | ${summarizeKind(obligations, 'axiom')} |`
    );
  }

  lines.push(
    '',
    '## Module Inventory',
    '',
    '| Module | MCP island | Obligations | sorry | admit | axiom | First locations |',
    '|---|---|---:|---:|---:|---:|---|'
  );

  for (const moduleAudit of [...moduleAudits].sort(
    (left, right) =>
      right.obligations.length - left.obligations.length ||
      left.moduleName.localeCompare(right.moduleName)
  )) {
    const locations = moduleAudit.obligations
      .slice(0, 5)
      .map(
        (obligation) =>
          `\`${obligation.kind}@${obligation.lineNumber}: ${obligation.snippet.replaceAll('|', '\\|')}\``
      )
      .join('<br>');
    lines.push(
      `| \`${moduleAudit.moduleName}\` | ${moduleAudit.server} | ${moduleAudit.obligations.length} | ${summarizeKind(moduleAudit.obligations, 'sorry')} | ${summarizeKind(moduleAudit.obligations, 'admit')} | ${summarizeKind(moduleAudit.obligations, 'axiom')} | ${locations} |`
    );
  }

  lines.push('');
  return lines.join('\n');
}

function main() {
  const moduleAudits = walkLeanFiles(gnosisMathRoot)
    .map((filePath) => {
      const moduleName = moduleNameFromPath(filePath);
      return {
        moduleName,
        server: likelyServerForModule(moduleName),
        obligations: scanObligations(filePath),
      };
    })
    .filter((moduleAudit) => moduleAudit.obligations.length > 0);

  writeFileSync(reportPath, renderReport(moduleAudits), 'utf8');
  console.log(`Wrote ${path.relative(process.cwd(), reportPath)}`);
}

main();
